import{_ as e,o as a,c as i,ag as n}from"./chunks/framework.DL0AyVxm.js";const k=JSON.parse('{"title":"CLAUDE.md Template","description":"","frontmatter":{},"headers":[],"relativePath":"reference/claude-md.md","filePath":"reference/claude-md.md"}'),t={name:"reference/claude-md.md"};function l(o,s,h,p,d,r){return a(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="claude-md-template" tabindex="-1">CLAUDE.md Template <a class="header-anchor" href="#claude-md-template" aria-label="Permalink to &quot;CLAUDE.md Template&quot;">​</a></h1><p>Worclaude generates a <code>CLAUDE.md</code> file at the project root during <code>worclaude init</code>. This file is the primary instruction set Claude reads at the start of every session and after every context compaction. It is deliberately kept short.</p><h2 id="why-40-lines" tabindex="-1">Why ~40 Lines <a class="header-anchor" href="#why-40-lines" aria-label="Permalink to &quot;Why ~40 Lines&quot;">​</a></h2><p>Claude reads CLAUDE.md on every session start and after every <code>/compact</code>. Every line consumes context budget on every interaction. The template targets roughly 40 lines of actual content to balance completeness with economy.</p><p>Detailed knowledge is pushed to skill files, which are loaded on demand. CLAUDE.md contains just enough for Claude to orient itself and pointers to deeper knowledge.</p><h2 id="template-structure" tabindex="-1">Template Structure <a class="header-anchor" href="#template-structure" aria-label="Permalink to &quot;Template Structure&quot;">​</a></h2><p>The generated CLAUDE.md has 7 sections:</p><h3 id="header" tabindex="-1">Header <a class="header-anchor" href="#header" aria-label="Permalink to &quot;Header&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># CLAUDE.md</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{project_name} — {description}</span></span></code></pre></div><p>The project name and one-line description from the <code>worclaude init</code> prompts. Gives Claude immediate project identity.</p><h3 id="key-files" tabindex="-1">Key Files <a class="header-anchor" href="#key-files" aria-label="Permalink to &quot;Key Files&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Key Files</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \`docs/spec/PROGRESS.md\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — Read first every session</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \`docs/spec/SPEC.md\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> — Source of truth</span></span></code></pre></div><p>Points Claude to the two most important documents. PROGRESS.md tracks session-to-session state. SPEC.md defines what the project should do. These are always listed first because the Session Protocol references them.</p><h3 id="tech-stack" tabindex="-1">Tech Stack <a class="header-anchor" href="#tech-stack" aria-label="Permalink to &quot;Tech Stack&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Tech Stack</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Python</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Node.js / TypeScript</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Docker</span></span></code></pre></div><p>Populated from the tech stack selections during init. Tells Claude what languages and tools are in play so it writes appropriate code and commands.</p><h3 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Commands</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\`bash</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Python</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pytest</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # Run tests</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ruff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # Lint</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ruff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> format</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                   # Format</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\`\`\`</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>Populated from the tech stack selections. Provides exact commands for testing, linting, and formatting so Claude does not guess or use incorrect tool names.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>### Skills</span></span>
<span class="line"><span></span></span>
<span class="line"><span>\`\`\`markdown</span></span>
<span class="line"><span>## Skills (read on demand, not upfront)</span></span>
<span class="line"><span>See \`.claude/skills/\` — load only what&#39;s relevant:</span></span>
<span class="line"><span>- context-management.md — Session lifecycle</span></span>
<span class="line"><span>- git-conventions.md — Commits and branches</span></span>
<span class="line"><span>- planning-with-files.md — Implementation planning</span></span>
<span class="line"><span>- review-and-handoff.md — Session endings</span></span>
<span class="line"><span>- verification.md — How to verify work</span></span>
<span class="line"><span>- testing.md — Test philosophy and patterns</span></span>
<span class="line"><span>- backend-conventions.md — Run /setup to fill automatically</span></span>
<span class="line"><span>- frontend-design-system.md — Run /setup to fill automatically</span></span>
<span class="line"><span>- project-patterns.md — Run /setup to fill automatically</span></span></code></pre></div><p>Lists all 9 universal skills and 3 template skills. The &quot;read on demand, not upfront&quot; instruction tells Claude not to load every skill at session start -- only when the current task needs it. This is the progressive disclosure pattern.</p><h3 id="session-protocol" tabindex="-1">Session Protocol <a class="header-anchor" href="#session-protocol" aria-label="Permalink to &quot;Session Protocol&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Session Protocol</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**Start:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Read PROGRESS.md. Read active implementation prompt if any.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**During:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> One task at a time. Commit after each. Use subagents for side work.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-light-font-weight:bold;--shiki-dark:#E1E4E8;--shiki-dark-font-weight:bold;">**End:**</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Update PROGRESS.md. Write handoff if ending mid-task.</span></span></code></pre></div><p>Three-line workflow protocol. Covers the full session lifecycle. Each phase has a corresponding slash command (<code>/start</code>, <code>/end</code>) and skill file for detailed guidance.</p><h3 id="critical-rules" tabindex="-1">Critical Rules <a class="header-anchor" href="#critical-rules" aria-label="Permalink to &quot;Critical Rules&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Critical Rules</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SPEC.md is source of truth. Do not invent features.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Test before moving on.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Ask if ambiguous. Do not guess.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Read source files before writing. Never assume.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Self-healing: same mistake twice → update CLAUDE.md.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">6.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Use subagents to keep main context clean.</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">7.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Mediocre fix → scrap it, implement elegantly.</span></span></code></pre></div><p>Seven rules that apply to every task. These prevent the most common failure modes: feature drift (rule 1), untested code (rule 2), silent assumptions (rules 3-4), repeated mistakes (rule 5), context bloat (rule 6), and low-quality patches (rule 7).</p><h3 id="gotchas" tabindex="-1">Gotchas <a class="header-anchor" href="#gotchas" aria-label="Permalink to &quot;Gotchas&quot;">​</a></h3><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Gotchas</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Grows during development]</span></span></code></pre></div><p>Starts empty. Grows organically as the project encounters problems. This is the self-healing mechanism -- when Claude makes the same mistake twice, a gotcha is added here to prevent it from happening again. The <code>/update-claude-md</code> command helps maintain this section.</p><h2 id="how-skills-are-referenced" tabindex="-1">How Skills Are Referenced <a class="header-anchor" href="#how-skills-are-referenced" aria-label="Permalink to &quot;How Skills Are Referenced&quot;">​</a></h2><p>CLAUDE.md lists skills by filename with a brief description, but does not inline their content. This is the pointer pattern:</p><ul><li>CLAUDE.md says: <code>context-management.md — Session lifecycle</code></li><li>Claude sees the pointer and knows the skill exists</li><li>When working on context management, Claude reads the full skill file</li><li>The skill&#39;s detailed content only enters context when needed</li></ul><p>This keeps CLAUDE.md small while making deep knowledge accessible.</p><h2 id="the-never-auto-merge-philosophy" tabindex="-1">The &quot;Never Auto-Merge&quot; Philosophy <a class="header-anchor" href="#the-never-auto-merge-philosophy" aria-label="Permalink to &quot;The &quot;Never Auto-Merge&quot; Philosophy&quot;">​</a></h2><p>CLAUDE.md is never automatically overwritten by <code>worclaude init</code> (Scenario B) or <code>worclaude upgrade</code>. When merging into a project that already has CLAUDE.md:</p><ul><li><strong>Scenario B (init with existing setup):</strong> Worclaude generates a <code>CLAUDE.md.workflow-suggestions</code> file with proposed content. The user decides what to adopt.</li><li><strong>Upgrade:</strong> CLAUDE.md is not touched at all.</li></ul><p>This is intentional. CLAUDE.md is expected to diverge from the template as the project evolves. Auto-merging would destroy project-specific rules, gotchas, and customizations.</p><h2 id="customization" tabindex="-1">Customization <a class="header-anchor" href="#customization" aria-label="Permalink to &quot;Customization&quot;">​</a></h2><p>After installation, users should:</p><ol><li>Run <code>/setup</code> to fill in tech stack details and commands with real project data.</li><li>Add project-specific critical rules as they emerge.</li><li>Let the Gotchas section grow naturally from development experience.</li><li>Keep the file under ~50 lines. Move detailed guidance to skill files.</li><li>Prune regularly -- remove rules for deleted code, consolidate duplicates.</li></ol><hr><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/Worclaude/reference/skills.html">Skills</a> -- the knowledge files referenced from CLAUDE.md</li><li><a href="/Worclaude/reference/slash-commands.html">Slash Commands</a> -- <code>/setup</code> populates CLAUDE.md, <code>/update-claude-md</code> maintains it</li><li><a href="/Worclaude/guide/getting-started.html">Getting Started</a> -- the init workflow that generates CLAUDE.md</li></ul>`,43)])])}const u=e(t,[["render",l]]);export{k as __pageData,u as default};
